var phaseOffset = random(0, Math.PI * 2);
var ampFactor = random(0.8, 1.2);
var freqOffset = random(0.9, 1.1);

if (frame < wiggleFrames) {
    var amp = maxAmp * ampFactor * Math.exp(-decay * t);

    var offsetX = amp * Math.sin((freq * freqOffset) * t * 2 * Math.PI + phaseOffset);
    var offsetY = amp * Math.cos((freq * freqOffset) * t * 2 * Math.PI + phaseOffset);

    base + [offsetX, offsetY];
} else {
    base;
}

